import { Component, OnDestroy } from '@angular/core';
import { Memoize } from '@acorex/core/memoize';

@Component({
  selector: 'app-example',
  template: `<p>Result: {{ result }}</p>`,
})
export class ExampleComponent implements OnDestroy {
  result = 0;

  @Memoize()
  expensiveCalculation(n: number): number {
    console.log('Calculating for:', n);
    let sum = 0;
    for (let i = 0; i < n; i++) {
      for (let j = 0; j < n; j++) {
        sum += i * j;
      }
    }
    return sum;
  }

  constructor() {
    this.result = this.expensiveCalculation(1000); // runs
    this.result = this.expensiveCalculation(1000); // cached — no log
    this.result = this.expensiveCalculation(500);  // runs again
  }

  ngOnDestroy() {
    // Custom cleanup — decorator clears memoize cache before/after this
  }
}

