import { inject } from '@angular/core';
import { AXFormatService } from '@acorex/core/format';
import { Memoize } from '@acorex/core/memoize';

export class AXDataTextColumnComponent {
  private formatService = inject(AXFormatService);

  format = 'number';
  formatOptions = { locale: 'en-US' };

  getCellDisplayText(rowData: unknown, dataField: string): string {
    if (rowData == null) return '';
    return this.getDisplayText(rowData, dataField);
  }

  @Memoize()
  protected getDisplayText(rowData: unknown, dataField: string): string {
    const value = (rowData as Record<string, unknown>)[dataField];
    return !this.format
      ? String(value ?? '')
      : this.formatService.format(value, this.format, this.formatOptions);
  }
}

// Note: if this.format or this.formatOptions change at runtime,
// include them in the method signature to avoid stale cache entries.

import { Memoize } from '@acorex/core/memoize';

export class FormatterComponent {
  format = 'number';
  locale = 'en-US';

  // ❌ Risky — format/locale not in cache key
  @Memoize()
  badFormat(value: number): string {
    return `${this.locale}:${this.format}:${value}`;
  }

  // ✅ Safe — all dependencies are arguments
  @Memoize()
  goodFormat(value: number, format: string, locale: string): string {
    return `${locale}:${format}:${value}`;
  }

  display(value: number) {
    return this.goodFormat(value, this.format, this.locale);
  }
}

import { Component, OnDestroy } from '@angular/core';
import { Memoize } from '@acorex/core/memoize';

@Component({ selector: 'app-demo', template: '' })
export class DemoComponent implements OnDestroy {
  @Memoize()
  compute(x: number) {
    return x * 2;
  }

  ngOnDestroy() {
    console.log('My cleanup runs');
    // Decorator wraps this: calls your hook, then memoizedMethod.clear()
  }
}

// Classes without ngOnDestroy still get one added by the decorator
